49	import { execFileSync } from 'node:child_process';
50	import { readFileSync, writeFileSync, existsSync, rmSync, mkdtempSync } from 'node:fs';
51	import { join } from 'node:path';
52	import { tmpdir } from 'node:os';
53	import { pathToFileURL } from 'node:url';
