55	const CANON_URL = 'https://github.com/missingbulb/Claudinite.git'; // public — no token
56	const MAINT_PREFIX = 'claudinite/maintenance';
57	const API = 'https://api.github.com';
58	
59	// --- pure helpers (exported, unit-tested git-free) --------------------------
60	
61	// The member's delivery preference, normalized. `push`/`auto` → auto-merge and
62	// `pr` → review are the permanent legacy aliases (same tolerance as fleet-apply);
63	// anything else is invalid (null) and fails the run rather than guessing.
64	export function normalizeDelivery(raw) {
65	  const v = String(raw ?? '').trim();
66	  if (v === 'auto-merge' || v === 'auto' || v === 'push') return 'auto-merge';
67	  if (v === 'review' || v === 'pr') return 'review';
68	  return null;
69	}
70	
71	// The pending AGENTIC notes: those dated on/after the DAY of the prior stamp
72	// (same-day inclusive, #330), oldest first. `agenticList` is registry.mjs
73	// `agenticMigrations(all)` — already filtered to records carrying a valid
74	// `agentic` note (a malformed note throws THERE, aborting the run loudly).
75	export function pendingAgentic(agenticList, priorUpdated) {
76	  const priorDay = String(priorUpdated ?? '').slice(0, 10);
77	  return [...(agenticList ?? [])]
78	    .filter((m) => !priorDay || String(m.landed) >= priorDay)
79	    .sort((a, b) => String(a.landed).localeCompare(String(b.landed)));
80	}
81	
82	// HOLD the stamp at the day before the earliest pending agentic note (the
83	// stamp/agentic coupling rule): the note stays selected next run until the agent
84	// lands it and advances the stamp itself. Returns the held ISO datetime, or null
85	// when nothing is pending (the stamp advances normally).
86	export function heldStamp(pending) {
87	  if (!pending?.length) return null;
88	  const d = new Date(`${String(pending[0].landed).slice(0, 10)}T00:00:00.000Z`);
89	  d.setUTCDate(d.getUTCDate() - 1);
90	  return d.toISOString();
91	}
92	
93	// A per-cycle maintenance branch name — dated + a short seed so each cycle gets a
94	// distinct branch (superseding #407's scheme, native-git side). `seed` is passed
95	// in so this is pure; main() generates it.
96	export function maintenanceBranchName(dateStr, seed) {
97	  return `${MAINT_PREFIX}-${dateStr}-${seed}`;
98	}
99	
100	// The head branch of the family's open maintenance PR, found by head-branch
101	// PREFIX (idempotency is by prefix now that the name carries a per-cycle seed):
102	// a run reuses that branch/PR so PRs never pile up night-over-night. null → mint
103	// a fresh one.
104	export function openMaintenanceBranch(pulls, prefix = MAINT_PREFIX) {
105	  const p = (pulls ?? []).find((pr) => String(pr?.head?.ref ?? '').startsWith(prefix));
106	  return p ? p.head.ref : null;
107	}
108	
109	// The escalation predicate (owner, 2026-07-23): agent iff a pending agentic note,
110	// or a real change the deterministic converge left non-green. No change, or a
111	// green change with no agentic note, stays agentless.
112	export function shouldRequestAgent({ pendingCount, meaningfulChange, checksPass }) {
113	  if (pendingCount > 0) return true;
114	  return Boolean(meaningfulChange) && !checksPass;
115	}
116	
117	// The scheduler hands the worker a path to signal the agent through; writing it
118	// requests the agent stage (run.mjs files `ready-for-agent` iff it appears).
119	export const AGENT_REQUEST_MARKER = 'agent-requested';
120	
121	// --- I/O shell (validated by the live pilot, not unit tests) ----------------
122	
123	const git = (args, opts = {}) =>
124	  execFileSync('git', args, { encoding: 'utf8', stdio: ['ignore', 'pipe', 'pipe'], ...opts });
125	const node = (args, extraEnv = {}) =>
126	  execFileSync(process.execPath, args, { encoding: 'utf8', stdio: ['ignore', 'pipe', 'pipe'], env: { ...process.env, ...extraEnv } });
127	
128	async function gh(token, path, { method = 'GET', body } = {}) {
129	  const res = await fetch(`${API}${path}`, {
130	    method,
131	    headers: {
132	      authorization: `Bearer ${token}`,
133	      accept: 'application/vnd.github+json',
134	      'x-github-api-version': '2022-11-28',
135	      ...(body ? { 'content-type': 'application/json' } : {}),
136	    },
137	    body: body ? JSON.stringify(body) : undefined,
138	  });
139	  let json = null;
140	  try { json = await res.json(); } catch { /* empty body */ }
141	  return { status: res.status, json };
142	}
143	
144	// Run check_the_world against the converged repo; true when it exits clean (no
145	// blocking findings). Any non-zero exit / throw means "not green" → judgment left.
146	function checkTheWorldPasses(root) {
147	  const cw = join(root, '.claudinite/shared/engine/checks/check_the_world.mjs');
148	  if (!existsSync(cw)) return true; // no vendored checks to gate on
149	  try { node([cw], { CLAUDE_PROJECT_DIR: root }); return true; }
150	  catch { return false; }
151	}
152	
153	// Deliver the converge as one commit on the per-cycle maintenance branch, native
154	// git. Reuses the family's open PR (by prefix) or mints a dated branch + PR;
155	// arms auto-merge when the member asked for it. Force-push is the regenerate-not-
156	// reconcile stance for this bot-owned branch.
157	async function deliver(root, repo, base, token, delivery, seed) {
158	  const { json: pulls } = await gh(token, `/repos/${repo}/pulls?state=open&per_page=100`);
159	  let branch = openMaintenanceBranch(Array.isArray(pulls) ? pulls : []);
160	  const reuse = Boolean(branch);
161	  if (!branch) branch = maintenanceBranchName(new Date().toISOString().slice(0, 10), seed);
162	
163	  git(['-C', root, 'checkout', '-B', branch]);
164	  git(['-C', root, 'add', '-A']);
165	  git(['-C', root, '-c', 'user.name=claudinite[bot]', '-c', 'user.email=claudinite@users.noreply.github.com',
166	    'commit', '-m', 'Claudinite maintenance: converge vendored mount, wiring, and migration notes']);
167	  const remote = `https://x-access-token:${token}@github.com/${repo}.git`;
168	  git(['-C', root, 'push', '--force', remote, `HEAD:refs/heads/${branch}`]);
169	
170	  if (!reuse) {
171	    const body = delivery === 'auto-merge'
172	      ? 'Automated Claudinite maintenance (deterministic converge + any migration notes). Regenerated each cycle; auto-merges once this repo\'s checks pass.'
173	      : 'Automated Claudinite maintenance (deterministic converge + any migration notes). Regenerated each cycle; left for your review.';
174	    const { json: pr } = await gh(token, `/repos/${repo}/pulls`, {
175	      method: 'POST', body: { head: branch, base, title: 'Claudinite maintenance', body },
176	    });
177	    if (delivery === 'auto-merge' && pr?.node_id) {
178	      // ARM GitHub's native auto-merge (not an immediate merge): the PR lands
179	      // automatically once this repo's required checks pass, and the run never
180	      // blocks on CI. Auto-merge is a GraphQL-only mutation. Best-effort — if the
181	      // repo hasn't enabled auto-merge, the PR simply stays open for review.
182	      await enableAutoMerge(token, pr.node_id).catch(() => {});
183	    }
184	  }
185	  return branch;
186	}
187	
188	// Arm native auto-merge on a PR (by node id) via the GraphQL mutation — the REST
189	// `PUT /merge` would merge NOW, ignoring pending checks; this waits for them.
190	async function enableAutoMerge(token, pullRequestId) {
191	  const query = 'mutation($id:ID!){enablePullRequestAutoMerge(input:{pullRequestId:$id,mergeMethod:SQUASH}){pullRequest{id}}}';
192	  const res = await fetch(`${API}/graphql`, {
193	    method: 'POST',
194	    headers: { authorization: `Bearer ${token}`, 'content-type': 'application/json' },
195	    body: JSON.stringify({ query, variables: { id: pullRequestId } }),
196	  });
197	  const json = await res.json().catch(() => null);
198	  if (json?.errors?.length) throw new Error(json.errors[0].message);
199	}
200	
201	export async function main() {
202	  const root = process.env.CLAUDINITE_REPO_ROOT || process.cwd();
203	  const repo = process.env.CLAUDINITE_REPO || process.env.GITHUB_REPOSITORY;
204	  const base = process.env.CLAUDINITE_DEFAULT_BRANCH || 'main';
205	  const token = process.env.GITHUB_TOKEN;
206	  const requestFile = process.env.CLAUDINITE_REQUEST_AGENT;
207	  if (!repo) { console.error('baselining: no repo (CLAUDINITE_REPO/GITHUB_REPOSITORY)'); process.exit(1); }
208	  if (!token) { console.error('baselining: no GITHUB_TOKEN in env'); process.exit(1); }
209	
210	  const checksPath = join(root, '.claudinite-checks.json');
211	  if (!existsSync(checksPath)) { console.log('baselining: no .claudinite-checks.json — nothing to self-refresh'); return; }
212	  const priorRaw = JSON.parse(readFileSync(checksPath, 'utf8'));
213	  const priorStamp = priorRaw.claudinite ?? {};
214	  if (!priorStamp.updated && !priorStamp.ref) {
215	    console.log('baselining: no vendored-mount stamp — nothing to self-refresh (canon home or pre-adoption)');
216	    return; // quiet, no agent (matches the precondition self-skip)
217	  }
218	  const delivery = normalizeDelivery(priorRaw?.maintenance?.delivery);
219	  if (!delivery) {
220	    console.error(`baselining: maintenance.delivery "${priorRaw?.maintenance?.delivery}" is neither auto-merge nor review`);
221	    process.exit(1);
222	  }
223	
224	  // 1. Fetch canon at head as a ROOTLESS tree (drop .git so apply-vendor-set's
225	  //    ancestry guards skip — a shallow clone can't answer them, and it is head
226	  //    by construction).
227	  const tmp = mkdtempSync(join(tmpdir(), 'claudinite-canon-'));
228	  git(['clone', '--depth', '1', CANON_URL, tmp]);
229	  const headSha = git(['-C', tmp, 'rev-parse', 'HEAD']).trim();
230	  rmSync(join(tmp, '.git'), { recursive: true, force: true });
231	
232	  // 2-4. Deterministic converge: mount + stamp, then wiring, then mechanical notes.
233	  node([join(tmp, 'vendoring/apply-vendor-set.mjs'), '--target', root, '--ref', headSha]);
234	  node([join(tmp, 'engine/scheduler/converge-wiring.mjs'), repo], { CLAUDINITE_REPO_ROOT: root });
235	  node([join(tmp, 'migrations/apply.mjs')], { CLAUDE_PROJECT_DIR: root });
236	
237	  // 5. Pending agentic notes (from the fresh canon clone) + stamp hold.
238	  const { loadMigrations, agenticMigrations } = await import(pathToFileURL(join(tmp, 'migrations/registry.mjs')).href);
239	  const pending = pendingAgentic(agenticMigrations(await loadMigrations()), priorStamp.updated);
240	  if (pending.length) {
241	    const raw = JSON.parse(readFileSync(checksPath, 'utf8'));
242	    raw.claudinite = { ...raw.claudinite, updated: heldStamp(pending) };
243	    writeFileSync(checksPath, JSON.stringify(raw, null, 2) + '\n');
244	  }
245	
246	  // 6. Meaningful change? A stamp-only bump against an unchanged head is not one —
247	  //    revert it and stay quiet (no nightly stamp-only noise).
248	  const changed = git(['-C', root, 'status', '--porcelain'])
249	    .split('\n').map((l) => l.slice(3)).filter(Boolean);
250	  const onlyStamp = changed.length > 0 && changed.every((p) => p === '.claudinite-checks.json');
251	  if (onlyStamp && priorStamp.ref === headSha && !pending.length) {
252	    git(['-C', root, 'checkout', '--', '.claudinite-checks.json']);
253	    console.log('baselining: mount already at canon head, nothing changed — agentless, quiet');
254	    return;
255	  }
256	  const meaningfulChange = changed.length > 0;
257	
258	  // 7. Escalation gate: run the conformance checks only when a change happened and
259	  //    no agentic note already forces the agent.
260	  const checksPass = (meaningfulChange && !pending.length) ? checkTheWorldPasses(root) : true;
261	  const requestAgent = shouldRequestAgent({ pendingCount: pending.length, meaningfulChange, checksPass });
262	
263	  // 8. Deliver the converge (only when there's something to land).
264	  if (meaningfulChange || pending.length) {
265	    const seed = Math.random().toString(36).slice(2, 8);
266	    const branch = await deliver(root, repo, base, token, delivery, seed);
267	    console.log(`baselining: delivered converge on ${branch} (${delivery})`);
268	  } else {
269	    console.log('baselining: no change to deliver');
270	  }
271	
272	  // 9. Request the agent only when judgment is left (conditional handoff, §3).
273	  if (requestAgent && requestFile) writeFileSync(requestFile, `${AGENT_REQUEST_MARKER}\n`);
274	  console.log(requestAgent
275	    ? `baselining: requested agent stage (${pending.length ? `${pending.length} agentic note(s)` : 'conformance not green'})`
276	    : 'baselining: agentless night — deterministic converge delivered, no agent needed');
277	}
278	
279	// Run only when invoked directly (the scheduler's `node worker.mjs`), never on
280	// import — a test imports the pure helpers without any git or network.
281	if (process.argv[1] && import.meta.url === pathToFileURL(process.argv[1]).href) {
282	  main().catch((e) => { console.error(`baselining preprocessing failed: ${e.message}`); process.exit(1); });
283	}
